function deepFreeze(value) {
  if (!value || typeof value !== 'object' || Object.isFrozen(value)) return value;
  Object.freeze(value);
  for (const child of Object.values(value)) deepFreeze(child);
  return value;
}

function arrayFrom(value) {
  return Array.isArray(value) ? value : [];
}

function normalizeTags(tags) {
  return Object.freeze([...new Set(arrayFrom(tags).map(normalizeCapabilityTag).filter(Boolean))]);
}

function aliasesFor(id, explicitAliases = []) {
  const aliases = new Set(explicitAliases);
  for (const [alias, target] of Object.entries(OBJECT_ID_ALIASES)) {
    if (target === id) aliases.add(alias);
  }
  aliases.delete(id);
  return Object.freeze([...aliases].sort());
}

function resolveScale(id, blueprint, halfSizes = {}) {
  const explicit = blueprint.scale;
  const halfSize = halfSizes[id];
  const halfW = explicit?.halfW ?? halfSize?.[0] ?? halfSize?.w ?? null;
  const halfD = explicit?.halfD ?? halfSize?.[1] ?? halfSize?.d ?? null;
  const width = Number.isFinite(halfW) ? Number((halfW * 2).toFixed(3)) : null;
  const depth = Number.isFinite(halfD) ? Number((halfD * 2).toFixed(3)) : null;
  const area = Number.isFinite(width) && Number.isFinite(depth) ? Number((width * depth).toFixed(3)) : null;
  return Object.freeze({
    units: explicit?.units || 'tile',
    halfW,
    halfD,
    width,
    depth,
    area,
    solid: explicit?.solid ?? Boolean(halfW && halfD),
    source: explicit?.source || (halfSize ? `FURNITURE_HALF_SIZES.${id}` : 'catalog blueprint'),
  });
}

export function getCatalogEntrySizeBucket(entryOrScale) {
  const scale = entryOrScale?.scale || entryOrScale || {};
  const area = Number.isFinite(scale.area) ? scale.area : (Number.isFinite(scale.halfW) && Number.isFinite(scale.halfD) ? scale.halfW * 2 * scale.halfD * 2 : null);
  if (!Number.isFinite(area)) return 'medium';
  return CATALOG_REGISTRY_SIZE_FILTERS.find(bucket => area <= bucket.maxArea)?.id || 'large';
}

export function getCatalogEntryInteractionMode(entry) {
  const isDecorative = (entry?.classifications || []).includes('decorative') || (entry?.tags || []).includes('world.decorate');
  return isDecorative ? 'decorative' : 'interactable';
}

function candidatePlacedInstanceIds(instance) {
  if (!instance || typeof instance !== 'object') return [];
  const candidates = [
    instance.catalogId,
    instance.objectCatalogId,
    instance.type,
    instance.furnitureType,
    instance.decorationType,
  ];
  return [...new Set(candidates.filter(value => typeof value === 'string' && value.trim()).map(value => value.trim()))];
}

export function resolveCatalogEntryForPlacedInstance(instance, registry = CATALOG_REGISTRY) {
  const source = registry && typeof registry.get === 'function' ? registry : CATALOG_REGISTRY;
  for (const candidate of candidatePlacedInstanceIds(instance)) {
    const entry = source.get(candidate);
    if (entry) return entry;
  }
  return null;
}

function normalizeBlueprint(blueprint, adapters = {}) {
  const id = normalizeObjectCatalogId(blueprint.id) || blueprint.id;
  const taxonomy = getPhase1ObjectTaxonomy(id);
  const objectDefinition = blueprint.objectCatalogId ? getObjectCatalogExample(blueprint.objectCatalogId) : null;
  const category = normalizeObjectCategory(blueprint.category || taxonomy?.primaryCategory || objectDefinition?.category) || 'decor';
  const display = getObjectCategoryDisplay(category);
  const tags = normalizeTags(blueprint.tags || objectDefinition?.tags || BASE_TAGS_BY_ID[id] || []);
  const interactionSpots = adapters.interactionSpots?.[id] || (Array.isArray(blueprint.interactionSpots) ? blueprint.interactionSpots : null) || (adapters.actionSpots?.[id] ? [adapters.actionSpots[id]] : []);
  const scale = resolveScale(id, blueprint, adapters.halfSizes || {});
  const classifications = Object.freeze(arrayFrom(blueprint.classifications || taxonomy?.classifications || objectDefinition?.classifications));
  const exteriorArea = getPhase1BExteriorAssetTaxonomy(id);
  const exteriorDisplay = exteriorArea ? getExteriorAreaCategoryDisplay(exteriorArea.primaryExteriorCategory) : null;

  return deepFreeze({
    id,
    objectCatalogId: blueprint.objectCatalogId || objectDefinition?.id || null,
    label: blueprint.label,
    name: blueprint.name || blueprint.label.replace(/^\S+\s*/, ''),
    category,
    subcategory: blueprint.subcategory || taxonomy?.subcategory || objectDefinition?.subcategory || null,
    secondaryCategories: Object.freeze(arrayFrom(blueprint.secondaryCategories || taxonomy?.secondaryCategories || objectDefinition?.secondaryCategories).map(normalizeObjectCategory).filter(Boolean)),
    classifications,
    roomThemes: Object.freeze(arrayFrom(blueprint.roomThemes || taxonomy?.roomThemes || objectDefinition?.roomThemes)),
    roomTypes: Object.freeze(arrayFrom(blueprint.roomTypes || taxonomy?.roomTypes || objectDefinition?.roomTypes).map(value => String(value).trim().toLowerCase()).filter(Boolean)),
    tags,
    exteriorArea: exteriorArea ? Object.freeze({
      primaryCategory: exteriorArea.primaryExteriorCategory,
      secondaryTags: Object.freeze(arrayFrom(exteriorArea.secondaryTags)),
      label: exteriorDisplay?.label || exteriorArea.primaryExteriorCategory,
    }) : null,
    scale,
    size: getCatalogEntrySizeBucket(scale),
    interactionMode: classifications.includes('decorative') || tags.includes('world.decorate') ? 'decorative' : 'interactable',
    interactionSpots: Object.freeze(interactionSpots.map(spot => Object.freeze({ ...spot, roles: Object.freeze(arrayFrom(spot.roles)) }))),
    uiActions: Object.freeze(arrayFrom(blueprint.uiActions).map(action => Object.freeze({ ...action }))),
    lifecycle: blueprint.lifecycle ? deepFreeze({ ...blueprint.lifecycle }) : null,
    aliases: aliasesFor(id, blueprint.aliases),
    editor: Object.freeze({
      visibility: blueprint.editor?.visibility || 'editor',
      visible: (blueprint.editor?.visibility || 'editor') === 'editor',
      order: blueprint.editor?.order ?? 100,
      categoryOrder: OBJECT_CATEGORY_EDITOR_ORDER.indexOf(category) + 1,
      label: display?.label || category,
      icon: display?.icon || '',
      color: display?.color || '#94a3b8',
    }),
    runtimeAdapters: Object.freeze({
      furnitureType: id,
      hasRuntimeHalfSize: Boolean(adapters.halfSizes?.[id]),
      hasActionSpot: Boolean(adapters.actionSpots?.[id]),
      interactionSpotIds: Object.freeze(interactionSpots.map(spot => spot.id || 'default')),
    }),
  });
}

export function buildCatalogRegistry({ blueprints = CATALOG_REGISTRY_BLUEPRINTS, halfSizes = {}, actionSpots = {}, interactionSpots = {} } = {}) {
  const entries = blueprints.map(blueprint => normalizeBlueprint(blueprint, { halfSizes, actionSpots, interactionSpots }));
  const byId = new Map();
  const aliases = new Map();
  for (const entry of entries) {
    if (byId.has(entry.id)) throw new Error(`Duplicate catalog registry id ${entry.id}`);
    byId.set(entry.id, entry);
    for (const alias of entry.aliases) aliases.set(alias, entry.id);
  }

  const categories = OBJECT_CATEGORY_EDITOR_ORDER.map(category => Object.freeze({
    id: category,
    display: getObjectCategoryDisplay(category),
    entries: Object.freeze(entries.filter(entry => entry.category === category).sort(compareEntries).map(entry => entry.id)),
  }));

  return deepFreeze({
    version: CATALOG_REGISTRY_API_VERSION,
    entries: Object.freeze(entries.sort(compareEntries)),
    categories: Object.freeze(categories),
    aliases: Object.freeze(Object.fromEntries([...aliases.entries()].sort(([a], [b]) => a.localeCompare(b)))),
    get(id) {
      const normalized = normalizeObjectCatalogId(id) || id;
      return byId.get(normalized) || byId.get(aliases.get(id)) || byId.get(aliases.get(normalized)) || null;
    },
    list({ visibleOnly = false, category = null, tag = null, classification = null, roomTheme = null, roomType = null, exteriorAreaCategory = null, exteriorTag = null, size = null, interactionMode = null, objectId = null } = {}) {
      const normalizedCategory = category ? normalizeObjectCategory(category) : null;
      const normalizedTag = tag ? normalizeCapabilityTag(tag) : null;
      const normalizedClassification = typeof classification === 'string' ? classification.trim().toLowerCase() : null;
      const normalizedRoomTheme = typeof roomTheme === 'string' ? roomTheme.trim().toLowerCase() : null;
      const normalizedRoomType = typeof roomType === 'string' ? roomType.trim().toLowerCase() : null;
      const normalizedExteriorAreaCategory = exteriorAreaCategory ? normalizeExteriorAreaCategory(exteriorAreaCategory) || String(exteriorAreaCategory).trim().toLowerCase() : null;
      const normalizedExteriorTag = exteriorTag ? normalizeExteriorAreaCategory(exteriorTag) || String(exteriorTag).trim().toLowerCase() : null;
      const normalizedSize = typeof size === 'string' ? size.trim().toLowerCase() : null;
      const normalizedInteractionMode = typeof interactionMode === 'string' ? interactionMode.trim().toLowerCase() : null;
      const normalizedObjectId = objectId ? normalizeObjectCatalogId(objectId) : null;
      return entries.filter(entry => {
        if (visibleOnly && !entry.editor.visible) return false;
        if (normalizedCategory && entry.category !== normalizedCategory && !entry.secondaryCategories.includes(normalizedCategory)) return false;
        if (normalizedTag && !entry.tags.includes(normalizedTag)) return false;
        if (normalizedClassification && !entry.classifications.includes(normalizedClassification)) return false;
        if (normalizedRoomTheme && !entry.roomThemes.map(theme => theme.toLowerCase()).includes(normalizedRoomTheme)) return false;
        if (normalizedRoomType && !entry.roomTypes.includes(normalizedRoomType)) return false;
        if (normalizedExteriorAreaCategory && entry.exteriorArea?.primaryCategory !== normalizedExteriorAreaCategory && !entry.exteriorArea?.secondaryTags.includes(normalizedExteriorAreaCategory)) return false;
        if (normalizedExteriorTag && entry.exteriorArea?.primaryCategory !== normalizedExteriorTag && !entry.exteriorArea?.secondaryTags.includes(normalizedExteriorTag)) return false;
        if (normalizedSize && entry.size !== normalizedSize) return false;
        if (normalizedInteractionMode && entry.interactionMode !== normalizedInteractionMode) return false;
        if (normalizedObjectId && entry.id !== normalizedObjectId && entry.objectCatalogId !== normalizedObjectId && !entry.aliases.includes(objectId)) return false;
        return true;
      }).sort(compareEntries);
    },
    suggestForTemplate({ category = null, tag = null, classification = null, roomTheme = null, roomType = null, exteriorAreaCategory = null, exteriorTag = null, size = null, interactionMode = null, objectId = null, visibleOnly = true } = {}) {
      return this.list({ visibleOnly, category, tag, classification, roomTheme, roomType, exteriorAreaCategory, exteriorTag, size, interactionMode, objectId });
    },
    resolvePlacedInstance(instance) {
      return resolveCatalogEntryForPlacedInstance(instance, this);
    },
  });
}

export function buildEditorFurnitureCatalog(blueprints = CATALOG_REGISTRY_BLUEPRINTS) {
  const registry = buildCatalogRegistry({ blueprints });
  const visibleEntries = registry.list({ visibleOnly: true });
  const grouped = {};
  for (const category of OBJECT_CATEGORY_EDITOR_ORDER) {
    const display = getObjectCategoryDisplay(category);
    grouped[display?.label || category] = visibleEntries
      .filter(entry => entry.category === category)
      .map(entry => Object.freeze({ type: entry.id, label: entry.label }));
  }
  return deepFreeze(grouped);
}

export function validateCatalogRegistry(registry) {
  const errors = [];
  if (!registry || registry.version !== CATALOG_REGISTRY_API_VERSION) errors.push('registry.version must match CATALOG_REGISTRY_API_VERSION');
  if (!Array.isArray(registry?.entries) || registry.entries.length === 0) errors.push('registry.entries must be a non-empty array');
  const ids = new Set();
  for (const entry of registry?.entries || []) {
    if (!entry.id || ids.has(entry.id)) errors.push(`duplicate or missing id ${entry.id || '<missing>'}`);
    ids.add(entry.id);
    if (!normalizeObjectCategory(entry.category)) errors.push(`${entry.id}.category must normalize to a known category`);
    if (!CATALOG_REGISTRY_VISIBILITY.includes(entry.editor?.visibility)) errors.push(`${entry.id}.editor.visibility must be valid`);
    if (!CATALOG_REGISTRY_SCALE_UNITS.includes(entry.scale?.units)) errors.push(`${entry.id}.scale.units must be valid`);
    if (typeof entry.scale?.halfW !== 'number' || typeof entry.scale?.halfD !== 'number') errors.push(`${entry.id}.scale half sizes must be numeric`);
    if (!Array.isArray(entry.tags)) errors.push(`${entry.id}.tags must be an array`);
    if (entry.exteriorArea && (!entry.exteriorArea.primaryCategory || !Array.isArray(entry.exteriorArea.secondaryTags))) errors.push(`${entry.id}.exteriorArea must include primaryCategory and secondaryTags`);
  }
  for (const [alias, id] of Object.entries(registry?.aliases || {})) {
    if (!ids.has(id)) errors.push(`alias ${alias} points to unknown id ${id}`);
  }
  return Object.freeze({ valid: errors.length === 0, errors: Object.freeze(errors) });
}

function compareEntries(a, b) {
  return (a.editor.categoryOrder - b.editor.categoryOrder) || (a.editor.order - b.editor.order) || a.label.localeCompare(b.label);
}

export const CATALOG_REGISTRY = buildCatalogRegistry();
